import{_ as t,o,c as a,a2 as r}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 41 — Jump List","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/41-jump-list.md","filePath":"chapters/41-jump-list.md"}'),i={name:"chapters/41-jump-list.md"};function d(c,e,s,n,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="chapter-41-—-jump-list" tabindex="-1">Chapter 41 — Jump List <a class="header-anchor" href="#chapter-41-—-jump-list" aria-label="Permalink to &quot;Chapter 41 — Jump List&quot;">​</a></h1><blockquote><p><em>&quot;Never lose your place again. Vim remembers where you&#39;ve been.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐⭐ Intermediate <strong>Estimated Reading Time:</strong> 10 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>The jump list tracks cursor positions as you navigate.</p><p>It lets you go back to previous locations.</p><hr><h1 id="jump-list-navigation" tabindex="-1">Jump List Navigation <a class="header-anchor" href="#jump-list-navigation" aria-label="Permalink to &quot;Jump List Navigation&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Ctrl+o</code></td><td>Jump to <strong>older</strong> position</td></tr><tr><td><code>Ctrl+i</code></td><td>Jump to <strong>newer</strong> position</td></tr><tr><td><code>:jumps</code></td><td>List jump list</td></tr></tbody></table><hr><h1 id="when-jumps-are-recorded" tabindex="-1">When Jumps Are Recorded <a class="header-anchor" href="#when-jumps-are-recorded" aria-label="Permalink to &quot;When Jumps Are Recorded&quot;">​</a></h1><p>Jumps are recorded for:</p><ul><li><code>gg</code>, <code>G</code> — file top/bottom</li><li><code>{line}G</code> — line number jump</li><li><code>/pattern</code>, <code>?pattern</code> — search</li><li><code>%</code> — matching bracket</li><li><code>(</code>, <code>)</code> — sentence jumps</li><li><code>{</code>, <code>}</code> — paragraph jumps</li><li>Marks like <code>&#39;a</code></li></ul><hr><h1 id="change-list" tabindex="-1">Change List <a class="header-anchor" href="#change-list" aria-label="Permalink to &quot;Change List&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>g;</code></td><td>Go to previous change position</td></tr><tr><td><code>g,</code></td><td>Go to next change position</td></tr><tr><td><code>:changes</code></td><td>List change list</td></tr></tbody></table><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li><code>Ctrl+o</code> goes back, <code>Ctrl+i</code> goes forward.</li><li><code>:jumps</code> shows jump history.</li><li><code>g;</code>/<code>g,</code> navigates edit positions.</li><li>Jumps are saved per window.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Jump to line 100, then press <code>Ctrl+o</code> to go back.</li><li>Use <code>gg</code> then <code>G</code>, then <code>Ctrl+o</code> twice.</li><li>Navigate changes with <code>g;</code> and <code>g,</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./42-change-list.html"><strong>Chapter 42 — Change List</strong></a></p><p>Track and navigate your edit history.</p>',28)])])}const m=t(i,[["render",d]]);export{u as __pageData,m as default};
